// Put the implementation in a struct so we don't pollute the top-level namespace
fileprivate struct UniffiCallbackInterfaceModelRunner {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    //
    // Store the vtable directly.
    static let vtable: UniffiVTableCallbackInterfaceModelRunner = UniffiVTableCallbackInterfaceModelRunner(
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            do {
                try FfiConverterTypeModelRunner.handleMap.remove(handle: uniffiHandle)
            } catch {
                print("Uniffi callback interface ModelRunner: handle missing in uniffiFree")
            }
        },
        uniffiClone: { (uniffiHandle: UInt64) -> UInt64 in
            do {
                return try FfiConverterTypeModelRunner.handleMap.clone(handle: uniffiHandle)
            } catch {
                fatalError("Uniffi callback interface ModelRunner: handle missing in uniffiClone")
            }
        },
        modelVersion: { (
            uniffiHandle: UInt64,
            uniffiOutReturn: UnsafeMutablePointer<RustBuffer>,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> String in
                guard let uniffiObj = try? FfiConverterTypeModelRunner.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return try uniffiObj.modelVersion(
                )
            }


            let writeReturn = { uniffiOutReturn.pointee = FfiConverterString.lower($0) }
            uniffiTraitInterfaceCallWithError(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn,
                lowerError: FfiConverterTypeModelError_lower
            )
        },
        infer: { (
            uniffiHandle: UInt64,
            logMel: RustBuffer,
            frames: UInt32,
            bands: UInt32,
            energyPeak: Int8,
            uniffiOutReturn: UnsafeMutablePointer<RustBuffer>,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> ModelOutput in
                guard let uniffiObj = try? FfiConverterTypeModelRunner.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return try uniffiObj.infer(
                     logMel: try FfiConverterSequenceFloat.lift(logMel),
                     frames: try FfiConverterUInt32.lift(frames),
                     bands: try FfiConverterUInt32.lift(bands),
                     energyPeak: try FfiConverterBool.lift(energyPeak)
                )
            }


            let writeReturn = { uniffiOutReturn.pointee = FfiConverterTypeModelOutput_lower($0) }
            uniffiTraitInterfaceCallWithError(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn,
                lowerError: FfiConverterTypeModelError_lower
            )
        }
    )

    // Rust stores this pointer for future callback invocations, so it must live
    // for the process lifetime (not just for the init function call).
    //
    // `nonisolated(unsafe)` is needed under Swift 6 strict concurrency.
    // This is safe because the pointee is initialized once during static init
    // and never mutated by either side of the FFI.  Its fields are C function pointers.
    nonisolated(unsafe) static let vtablePtr: UnsafePointer<UniffiVTableCallbackInterfaceModelRunner> = {
        let ptr = UnsafeMutablePointer<UniffiVTableCallbackInterfaceModelRunner>.allocate(capacity: 1)
        ptr.initialize(to: vtable)
        return UnsafePointer(ptr)
    }()
}

