            return handleMap.insert(obj: value)
         }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ModelRunner {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: ModelRunner, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
